"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[4114],{535(e,t,o){o.r(t),o.d(t,{assets:()=>r,contentTitle:()=>h,default:()=>c,frontMatter:()=>a,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-11","title":"Discourses \u2014 Book 1, Chapter 11","description":"Book 1 \u2014 Chapter 11","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-11.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-11","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-11","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":11,"frontMatter":{"sidebar_position":11,"title":"Discourses \u2014 Book 1, Chapter 11","sidebar_label":"Book 1, Ch. 11"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 10","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-10"},"next":{"title":"Book 1, Ch. 12","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-12"}}');var n=o(4848),i=o(8453);const a={sidebar_position:11,title:"Discourses \u2014 Book 1, Chapter 11",sidebar_label:"Book 1, Ch. 11"},h="Discourses",r={},d=[{value:"Book 1 \u2014 Chapter 11",id:"book-1--chapter-11",level:2},{value:"On Family Affection",id:"on-family-affection",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(t.h2,{id:"book-1--chapter-11",children:"Book 1 \u2014 Chapter 11"}),(0,n.jsx)(t.h3,{id:"on-family-affection",children:"On Family Affection"})]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(o,{open:!0,children:[(0,n.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,n.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,n.jsx)(t.p,{children:"A dialogue with an official who fled his sick daughter out of distress, then justified it as \"natural.\" Epictetus's method here is characteristically Socratic: he doesn't attack the man but walks him through the logic of his own position until it collapses."}),(0,n.jsx)(t.p,{children:"The argument: if fleeing was the right expression of affection, then the mother, nurse, and attendant should all have fled too \u2014 leaving the child alone and helpless precisely because everyone loved her. The absurdity is self-evident. What the man called affection was actually something else entirely: a kind of mental disturbance, the same impulse that makes a man cover his eyes when his horse is running and faint when it wins."}),(0,n.jsx)(t.p,{children:'The deeper point is that our actions are always driven by our judgments \u2014 by how we are "minded." Achilles didn\'t mourn because Patroclus died; plenty of men lose companions without reacting that way. He mourned because he was so minded. This is liberating and demanding at once: if our judgments cause our distress, then our judgments are where the work must be done. No blaming wife, children, neighbors. The chapter ends with a quiet warning: investigating your own judgments is not the work of an hour or a day.'})]}),"\n",(0,n.jsxs)(o,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(t.h2,{id:"text",children:"Text"}),(0,n.jsx)(t.p,{children:"WHEN an official came to Epictetus and inquired for special directions he asked whether he had a wife and children; and when the man said, 'Yes', he asked again, How do you get on?"}),(0,n.jsx)(t.p,{children:"'Miserably', he said."}),(0,n.jsx)(t.p,{children:"What do you mean? said he; Men do not marry and have children to the end that they may be miserable, but rather that they may be happy."}),(0,n.jsx)(t.p,{children:"'Ah', said he, 'but I am so miserable about my poor children, that lately when my daughter was ill and was thought to be in danger I could not bear to be near her, but fled away from her, until some one brought me news that she was well.'"}),(0,n.jsx)(t.p,{children:"Well, do you think you were right to do it?"}),(0,n.jsx)(t.p,{children:"'It was natural', he said."}),(0,n.jsx)(t.p,{children:"Nay, said the master, only convince me that it was natural, and I will convince you that everything that is natural is right."}),(0,n.jsx)(t.p,{children:"'All fathers', he said, 'or most of us, at least, feel like that.'"}),(0,n.jsx)(t.p,{children:"I do not deny, said Epictetus, that parents feel so, but the real question is whether it is right. No doubt as far as that goes, we must say that even tumours come into being for the good of the body, and in"}),(0,n.jsx)(t.p,{children:"a word that error is natural, for nearly all, or most of us at least, are prone to error. Prove to me then how it is natural."}),(0,n.jsx)(t.p,{children:"'I cannot'; he said, 'rather do you prove to me how it is wrong or unnatural.'"}),(0,n.jsx)(t.p,{children:"He answered, Suppose we were discussing black and white, what test should we call in to distinguish between them?"}),(0,n.jsx)(t.p,{children:"'The sight', he said."}),(0,n.jsx)(t.p,{children:"What if we were discussing things hot or cold, hard and soft, what test should we use?"}),(0,n.jsx)(t.p,{children:"'Touch.'"}),(0,n.jsx)(t.p,{children:"Well then, as we are discussing what is natural and right and the opposite, what test would you have us take?"}),(0,n.jsx)(t.p,{children:"'I do not know', said he."}),(0,n.jsx)(t.p,{children:"Look here, it is no great loss perhaps not to know the proper test for colours and smells, nay, and flavours too, but do you think it is a small loss to man not to know what is good and what is evil, what is natural and what is unnatural?"}),(0,n.jsx)(t.p,{children:"'No, the greatest possible loss.'"}),(0,n.jsx)(t.p,{children:"Tell me now, is everything right which seems noble and fitting to certain people? To-day, for instance, are the opinions of Jews and Syrians, Egyptians and Romans, as to food all of them right?"}),(0,n.jsx)(t.p,{children:"'How can they be?'"}),(0,n.jsx)(t.p,{children:"No, I suppose if the Egyptians' views are right the other nations' must of necessity be wrong; if the Jews' opinions are good, other people's must be bad."}),(0,n.jsx)(t.p,{children:"'Of course.'"}),(0,n.jsx)(t.p,{children:"And where there is ignorance, there is also want of insight and education as to necessary things."}),(0,n.jsx)(t.p,{children:"'Yes.'"}),(0,n.jsx)(t.p,{children:"When once you have realized this, then, said Epictetus, you will make this your one interest in the future, and to this alone devote your mind--to discover the means of judging what is natural and to use your criterion to distinguish each particular case as it arises."}),(0,n.jsx)(t.p,{children:"For the present I can help you just so far as this in regard to what you wish: do you think family affection is natural and good? 'Of course.'"}),(0,n.jsx)(t.p,{children:"Again, is it true that affection is natural and good, and reason not good?"}),(0,n.jsx)(t.p,{children:"'Certainly not.'"}),(0,n.jsx)(t.p,{children:"Is there a conflict then between reason and affection?"}),(0,n.jsx)(t.p,{children:"'I think not.'"}),(0,n.jsx)(t.p,{children:"If there were a conflict, then, as one of the two is natural, the other must needs be unnatural?"}),(0,n.jsx)(t.p,{children:"'Certainly', he said."}),(0,n.jsx)(t.p,{children:"It follows then that whenever we find reason and affection united in an action, we confidently affirm that it is right and good."}),(0,n.jsx)(t.p,{children:"'Granted', he said."}),(0,n.jsx)(t.p,{children:"Mark what follows. I do not think you will deny that it is not reasonable to leave one's child when it is ill and to go away. The only question left for us is to consider whether it is affectionate."}),(0,n.jsx)(t.p,{children:"'Let us consider it then.'"}),(0,n.jsx)(t.p,{children:"Was it right, I ask, for you, being affectionately disposed to your child, to run away and leave her? Is her mother not fond of the child?"}),(0,n.jsx)(t.p,{children:"'She is indeed.'"}),(0,n.jsx)(t.p,{children:"Should the mother then have left her too, or should she not?"}),(0,n.jsx)(t.p,{children:"'She should not.'"}),(0,n.jsx)(t.p,{children:"What of the nurse? Is she fond of the child?"}),(0,n.jsx)(t.p,{children:"'She is', he said."}),(0,n.jsx)(t.p,{children:"Ought she then to have left her?"}),(0,n.jsx)(t.p,{children:"'By no means.'"}),(0,n.jsx)(t.p,{children:"Again, is not the child's attendant fond of her?"}),(0,n.jsx)(t.p,{children:"'He is.'"}),(0,n.jsx)(t.p,{children:"Ought he then to have gone away and left her? Was it right that as a consequence the child should be thus left desolate and helpless because of the great affection of you its parents and of those about it, or should die in the hands of those who had no love or care for it?"}),(0,n.jsx)(t.p,{children:"'Heaven forbid!'"}),(0,n.jsx)(t.p,{children:"Once more, it is not fair or reasonable, is it, that a man should not allow others equally affectionate with himself to do what, because he is affectionate, he thinks proper for himself. It is absurd. Tell me, would you have liked, if you were ill, your relations and every one else, even your wife and children, to show their affection for you in such a way as to leave you alone and desolate?"}),(0,n.jsx)(t.p,{children:"'Certainly not.'"}),(0,n.jsx)(t.p,{children:"Would you pray to be so loved by your own people, as to be always left alone by them when you were ill, because of their exceeding affection, or would you, if it were a question of being left alone, rather pray, supposing that were possible, to have the affection of your enemies? And if that is so, we are forced to the conclusion that your conduct was not that of affection."}),(0,n.jsx)(t.p,{children:"What reason had you then? Was there nothing which moved and impelled you to abandon the child? How is that possible? It must have been the same sort of motive, which once made a man in Rome cover his eyes when the horse he had backed was running, and then again when the horse unexpectedly won made him faint so that he needed sponges to recover him. What is the motive? This perhaps is not the moment"}),(0,n.jsx)(t.p,{children:"to define it; but it is enough that we should be convinced of this --if what philosophers say is sound--that we must not look for it somewhere outside us, but that it is always one and the same motive which causes us to do or not to do a thing, to speak or not to speak, to be elated or depressed, to fly or to pursue--the very motive which has moved you and me at this moment, you to come and sit and listen to me, and me to say what I do. What is the motive? Surely it is nothing but this--that we are so minded?"}),(0,n.jsx)(t.p,{children:"'Nothing else.'"}),(0,n.jsx)(t.p,{children:"And if things had looked different to us, we should still have done what we were minded to do and nothing else. So when Achilles mourned, his reason was, not the death of Patroclus--for another man, when his comrade dies, is not thus affected--but that he was so minded. So in your case, you ran away just because you were so minded; and again, if you stay it will be because you are so minded. And now you return to Rome, because you have a mind to do so; and if your mind changes, you will not depart thither. And in a word it is not death nor exile nor pain nor any such thing which is the cause of our action or inaction, but thoughts and judgements of the mind. Are you convinced of this or not?"}),(0,n.jsx)(t.p,{children:"'I am', he said."}),(0,n.jsx)(t.p,{children:"Then on each occasion the effects of an action correspond to the causes. So henceforward whenever we do a thing wrong, we shall blame nothing else but the judgement which led us to do it, and we shall try to remove and extirpate this even more than we do tumours and abscesses from the body. And so also we shall assert that our right actions are determined in the same way; and we shall no longer blame neighbour or wife or children as though they caused evils to befall us, being convinced that, unless we make up our mind that things are such, we' do not act as though they were, but that whether we judge them to be so or not depends upon ourselves and not on anything outside us."}),(0,n.jsx)(t.p,{children:"'True', he said."}),(0,n.jsx)(t.p,{children:"From this day forward then we shall not investigate or examine the nature or condition of anything else--whether it be land or slaves or horses or dogs--but only our own judgements."}),(0,n.jsx)(t.p,{children:"'I hope so', said he."}),(0,n.jsx)(t.p,{children:"You see then that you must become a student--that creature whom all mock at--if you really wish to investigate your judgements. That this is not the work of an hour or a day you fully understand without my telling you."})]})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>h});var s=o(6540);const n={},i=s.createContext(n);function a(e){const t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function h(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:a(e.components),s.createElement(i.Provider,{value:t},e.children)}}}]);